using namespace std;

int main() {
    Array arr1(5);
    cout << "Created array with capacity: " << arr1.getCapacity() << endl;

    arr1.setValue(0, 10);
    arr1.setValue(1, 20);
    arr1.setValue(2, 30);

    cout << "After setting values:" << endl;
    display(arr1);

    Array arr2 = arr1;
    cout << "Copy constructor test:" << endl;
    display(arr2);

    Array arr3;
    arr3 = arr1;
    cout << "Assignment operator test:" << endl;
    display(arr3);

    arr1.reSize(8);
    cout << "After resizing to 8:" << endl;
    display(arr1);

    return 0;
}
